python3 - <<'PY'
import requests,re
for pt in ['single','week','month','admin']:
    t=requests.post('http://web.chal.csaw.io:5800/displaydetails',data={'passType':pt},timeout=10).text
    print('===',pt,'===')
    for line in t.splitlines():
        if 'form' in line.lower() or 'input' in line.lower() or 'button' in line.lower() or 'price' in line.lower() or 'admin' in line.lower() or 'update' in line.lower():
            print(line)
PY

python3 - <<'PY'
import requests
for path in ['/','/admin','/update','/fare','/prices','/changeprice','/changeticket','/ticket','/home']:
    try:
        r=requests.get('http://web.chal.csaw.io:5800'+path,allow_redirects=False,timeout=10)
        print(path,r.status_code,r.headers.get('Location'),r.text[:300].replace('\n',' '))
    except Exception as e:
        print(path,e)
